        "Time and unit weights together soften sensitivity to level shifts"
      ],
      "package": "synthdid",
      "citation_keys": [
        "Arkhangelsky2021",
        "BenMichael2021",
        "Liu2024"
      ],
      "code": "library(synthdid)\nsetup <- panel.matrices(df, unit = 'id', time = 'year',\n                        outcome = 'y', treatment = 'D')\nsdid <- synthdid_estimate(setup$Y, setup$N0, setup$T0)\nsummary(sdid)",
      "flags": {
        "binary_only": false,
        "heterogeneity_robust": true,
        "no_dedicated_package": false
      }
    },
    "leaf_fect_few_cts": {
      "type": "leaf",
      "id": "leaf_fect_few_cts",
