      ],
      "package": "did (continuous branch), synthdid",
      "citation_keys": [
        "CallawayGBSA2024",
        "BenMichael2021",
        "Arkhangelsky2021"
      ],
      "code": "# Callaway/Goodman-Bacon/Sant'Anna (2024) continuous-treatment workflow,\n# applied cohort by cohort. With only 2–9 treated units, inference is thin —\n# pair with dose-binned synthetic control as a sanity check.",
